      <h2>◈ Character Details</h2>
      <div class="input-group">
        <input type="text" id="charName" placeholder="Character Name">
        <select id="charType" style="margin-top: 0.5rem;">
          <option value="">Select Type</option>
          <option value="companion">Companion</option>
          <option value="expert">Expert</option>
          <option value="character">Character</option>
          <option value="narrator">Narrator</option>
        </select>
        <textarea id="charPersona" placeholder="Personality and behavior instructions"></textarea>
        <textarea id="charContext" placeholder="Background context / scenario"></textarea>
        <div id="templateTags"></div>
      </div>
      <button class="btn" onclick="saveCharacter()">Save Character</button>
    </div>

    <!-- Character List -->
    <div class="section">
      <h2>◉ Characters</h2>
      <div id="characterList" class="character-list">
        <p style="color: #888; text-align: center; padding: 2rem;">No characters yet.</p>
      </div>
    </div>

    <div id="status" class="status"></div>
  </div>

  <script>
    // Character storage
    let characters = JSON.parse(localStorage.getItem('nexus_characters') || '[]');

    const templates = {
      companion: {
        type: 'companion',
        persona: 'Helpful AI assistant. Warm, engaging, and focused on supporting the user. Asks clarifying questions when needed.',
        context: 'You are a helpful AI assistant. Your goal is to be genuinely useful while being warm and engaging.',
        tags: ['helpful', 'warm', 'curious']
      },
      expert: {
        type: 'expert',
        persona: 'Domain expert. Precise, knowledgeable, and thorough. Explains complex concepts clearly.',
        context: 'You are an expert in [field]. Provide accurate, well-researched information with citations when possible.',
        tags: ['precise', 'knowledgeable', 'thorough']
      },
      character: {
        type: 'character',
        persona: '[Character name and distinct personality traits]. Has clear motivations, speech patterns, and perspective.',
        context: 'You are [character] in [setting]. Respond in character with [personality traits] and [speech mannerisms].',
        tags: ['roleplay', 'in-character', 'distinct']
      },
      narrator: {
        type: 'narrator',
        persona: 'Scenario narrator. Describes events, settings, and NPCs. Sets scene and builds narrative tension.',
        context: 'You are the narrator for [scenario]. Describe the world, portray characters, and advance the story based on user actions.',
        tags: ['storytelling', 'descriptive', 'scenario-based']
      }
    };

    function quickCreate() {
      const name = document.getElementById('quickName').value.trim();
      if (!name) {
        showStatus('Please enter a character name', 'error');
        return;
      }

      document.getElementById('charName').value = name;
      document.getElementById('charType').value = 'companion';
      applyTemplate();
      showStatus(`Created "${name}" using companion template. Edit details and save.`, 'success');
    }

    function applyTemplate() {
      const selected = document.getElementById('templateSelect').value;
      if (!selected) {
        showStatus('Please select a template', 'error');
        return;
      }

      const template = templates[selected];
      document.getElementById('charType').value = template.type;
      document.getElementById('charPersona').value = template.persona;
      document.getElementById('charContext').value = template.context;

      const tagsEl = document.getElementById('templateTags');
      tagsEl.innerHTML = template.tags.map(t => `<span class="tag">${t}</span>`).join('');

      showStatus('Template loaded. Customize and save.', 'success');
    }

    function saveCharacter() {
      const name = document.getElementById('charName').value.trim();
      const type = document.getElementById('charType').value;
      const persona = document.getElementById('charPersona').value.trim();
      const context = document.getElementById('charContext').value.trim();

      if (!name) {
        showStatus('Character name is required', 'error');
        return;
      }

      const character = {
        id: Date.now().toString(),
        name,
        type: type || 'companion',
        persona,
        context,
        created: new Date().toISOString()
      };

      characters.push(character);
      localStorage.setItem('nexus_characters', JSON.stringify(characters));

      renderCharacters();
      clearForm();
      showStatus('Character saved successfully', 'success');
    }

    function deleteCharacter(id, event) {
      event.stopPropagation();
      characters = characters.filter(c => c.id !== id);
      localStorage.setItem('nexus_characters', JSON.stringify(characters));
      renderCharacters();
      showStatus('Character deleted', 'success');
    }

    function renderCharacters() {
      const listEl = document.getElementById('characterList');

      if (characters.length === 0) {
        listEl.innerHTML = '<p style="color: #888; text-align: center; padding: 2rem;">No characters yet.</p>';
        return;
      }

      listEl.innerHTML = characters.map(char => `
        <div class="character-card" onclick="loadCharacter('${char.id}')">
          <div>
            <div class="character-name">${char.name}</div>
            <div class="character-type">${char.type} • ${new Date(char.created).toLocaleDateString()}</div>
          </div>
          <button class="delete-btn" onclick="deleteCharacter('${char.id}', event)">×</button>
        </div>
      `).join('');
    }

    function loadCharacter(id) {
      const char = characters.find(c => c.id === id);
      if (!char) return;

      document.getElementById('charName').value = char.name;
      document.getElementById('charType').value = char.type;
      document.getElementById('charPersona').value = char.persona;
      document.getElementById('charContext').value = char.context;

      showStatus(`Loaded "${char.name}" for editing`, 'success');
    }

    function clearForm() {
      document.getElementById('quickName').value = '';
      document.getElementById('charName').value = '';
      document.getElementById('charType').value = '';
      document.getElementById('charPersona').value = '';
      document.getElementById('charContext').value = '';
      document.getElementById('templateSelect').value = '';
      document.getElementById('templateTags').innerHTML = '';
    }

    function showStatus(msg, type) {
      const statusEl = document.getElementById('status');
      statusEl.textContent = msg;
      statusEl.className = `status ${type}`;
      setTimeout(() => statusEl.className = 'status', 3000);
    }

    // Initial render
    renderCharacters();
  </script>
</body>
</html>
